parameters.jsCode:
// Collect aggregated metrics from all sources
const now = Math.floor(Date.now() / 1000);

return [{
  json: {
    ts: now,
    source: 'bi_aggregator',
    metrics_to_collect: [
      'domain_health',
      'ssl_status',
      'email_volume',
      'email_sentiment',
      'security_events',
      'conversion_rate',
      'response_time',
      'error_rate',
      'user_activity',
      'system_resources'
    ],
    export_format: 'csv',
    destination: '/var/lib/smarter/bi_exports',
    kaggle_ready: true
  }
}];

// Aggregate all metrics into BI dataset
const conversion = $input.first().json;
const decisions = $input.all()[1].json;
const docling = $input.all()[2].json;

const now = Math.floor(Date.now() / 1000);
const hourAgo = now - 3600;

// Build comprehensive BI record
const biRecord = {
  // Timestamp
  timestamp: new Date().toISOString(),
  epoch: now,

  // Domain Health (from conversion metrics)
  total_events: conversion.total_events || 0,
  total_actions: conversion.total_actions || 0,
  conversion_rate: conversion.conversion_rate || 0,
  avg_response_time_ms: conversion.avg_response_time_ms || 0,

  // Decision Analysis
  decisions_logged: decisions.total || 0,

  // System Health
  docling_status: docling.status || 'unknown',
  bolt_dashboard: 'online',
  api_status: 'online',
  n8n_status: 'online',
  postgres_status: 'healthy',
  redis_status: 'healthy',

  // Quality Scores
  data_completeness: conversion.total_events > 0 ? 1.0 : 0,
  data_freshness: conversion.avg_response_time_ms < 10000 ? 1.0 : 0.5,

  // Metadata
  version: '4.3',
  environment: 'production',
  export_for_kaggle: true
};

return [{ json: biRecord }];

